"""
MKT Original — Mark 15-16
Output: data/commentary/mkt-original/mark.json
Skips already-present: 15:34, 15:39, 16:6

Key decisions:
- 15:2 sy legeis: treated as an ambiguous affirmation (the word is yours)
- 15:7 Barabbas: the son-of-the-father irony noted
- 15:28: included (in interlinear) with textual note — absent from best MSS
- 15:38 schizo: connected to baptism rending of heavens (1:10)
- 16:8 ephugon gar: discussed as authentic ending of Gospel
- 16:9-20 longer ending: identified as later addition (absent Sinaiticus, Vaticanus)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MARK_15_16 = {
"15": {
"1": "<p><strong>prōi / symboylion hetoimasantes / dēsantes / Pilatō paredōkan</strong> — very early / having made a plan / having bound / handed over to Pilate — <em>prōi</em> (very early morning — the fourth watch, before dawn). <em>Symboylion hetoimasantes</em> (having made/prepared a plan) — the formal council decision for delivery to Roman authority. <em>Dēsantes</em> (having bound Jesus) — the binding that continues from the arrest (14:46). <em>Paredōkan</em> (handed over — aorist of <em>paradidōmi</em>) — the chain of betrayal reaches Pilate: from Judas (14:10) to the priests (14:53) to Pilate. <em>Hēgemōni</em> (governor — the Roman title for the prefect of Judea).</p>",
"2": "<p><strong>sy ei ho basileus tōn Ioudaiōn / sy legeis</strong> — are you the king of the Jews? / you say it — <em>basileus tōn Ioudaiōn</em> (King of the Jews) — the Roman political charge, appearing five times in Mark 15 (vv.2, 9, 12, 18, 26). <em>Sy legeis</em> (you say so / that is your word) — an affirmation but not a straightforward yes. The construction is the same as in 14:62 where Jesus replied to a different question with <em>egō eimi</em>. Here the response is more distancing: the title is Pilate's framing, not Jesus's preferred category. Some translators render it as acknowledgment; others as subtle qualification.</p>",
"3": "<p><strong>katēgoroun / polla</strong> — were accusing / many things — the imperfect <em>katēgoroun</em> (were accusing, kept accusing — continuous action) pictures sustained pressure from the chief priests. <em>Polla</em> (many things) without specification — the plural accusations are left vague; what matters narratively is that Jesus does not respond to any of them (v.5). The charges were presumably expanded from the Sanhedrin proceedings (14:55–64) into Roman political language.</p>",
"4": "<p><strong>oudeno apokriē / posa sou katamarturousin</strong> — you answer nothing / how many things they testify against you — Pilate's astonishment at Jesus's silence is introduced with his second direct question. The cumulative weight of multiple accusers pressing charges while the accused stands mute is extraordinary. Isaiah 53:7 (the silent servant) provides the scriptural frame, though Mark does not cite it explicitly here.</p>",
"5": "<p><strong>ouketi ouden apekrinatō / thaumazein</strong> — he answered nothing more / to be amazed — <em>ouketi ouden</em> (no longer anything — emphatic double negation). <em>Thaumazein ton Pilaton</em> (Pilate to be amazed) — <em>thaumazō</em> is Mark's word for Jesus's own astonishment at unbelief (6:6) and for the crowds' amazement at his teaching. Here Pilate the pagan administrator is amazed at Jesus's self-mastery. The reversal is pointed: the one with Roman authority is confounded by the prisoner.</p>",
"6": "<p><strong>apolyen auton hena desmon / paretounto</strong> — he would release one prisoner / they would request — <em>apolyen</em> (imperfect — he used to release, it was his custom); the construction describes the Passover amnesty as a repeating practice. <em>Desmon</em> (prisoner, bound one). The historicity of this custom has been debated — it is not attested in Roman or Jewish sources outside the Gospels — but may represent a local accommodation to Jewish festival expectations.</p>",
"7": "<p><strong>Barabbas / stasiastais / phonon pepoiēkei en tē stasei</strong> — Barabbas / insurrectionists / had committed murder in the insurrection — <em>Barabbas</em> is Aramaic <em>bar Abbas</em> (son of Abbas or son of the father — <em>abba</em>). The naming choice creates a profound irony: the crowd releases a murderous <em>bar Abbas</em> (son of the father) and demands the death of the one who truly is the Son of the Father. <em>Stasiastai</em> (rebels, insurrectionists) and <em>phonos</em> (murder) — Barabbas is the genuine political criminal that Rome accused Jesus of being.</p>",
"8": "<p><strong>anaboēsas / parekalei</strong> — crying out / began to ask — <em>anaboēsas</em> (crying out, going up crying — the <em>ana-</em> prefix may indicate the crowd surging forward). The imperfect <em>parekalei</em> (were asking) describes the crowd petitioning Pilate to honor the release custom. The crowd's demand is distinct from the chief priests' manipulation (v.11) — they initially only want the customary release, not specifically the death of Jesus.</p>",
"9": "<p><strong>thelete apolyso hymin ton basilea tōn Ioudaiōn</strong> — do you want me to release to you the King of the Jews? — Pilate offers Jesus using the title the priests used in the charge. The question is politically loaded: accepting the release implicitly endorses the Messianic claim the priests are trying to suppress. The crowd's eventual rejection of this offer is engineered by the priests (v.11), not spontaneous.</p>",
"10": "<p><strong>eginōsken hoti dia phthonon</strong> — he knew that out of envy — <em>phthonos</em> (envy, jealous resentment — one of the vices listed in Paul's catalogs, e.g. Rom 1:29; Gal 5:21; the word for the malicious begrudging of another's status or success). Pilate reads the priests' motive correctly: Jesus's popularity threatens their institutional power. This is the narrator's direct attribution of motive, a rare moment of interiority given to the Roman governor.</p>",
"11": "<p><strong>aneseisan ton ochlon</strong> — stirred up the crowd — <em>anaseiō</em> (to shake up, agitate, stir — a vivid verb for rabble-rousing; <em>ana-</em> = upward motion + <em>seiō</em> = to shake). The chief priests actively work the crowd to redirect the Passover amnesty demand toward Barabbas. The manipulation is openly narrated: the crowd's eventual cry is orchestrated, not organic.</p>",
"12": "<p><strong>ti oun poiēsō... ton basilea tōn Ioudaiōn</strong> — what then shall I do with the King of the Jews? — Pilate's question uses the royal title again, perhaps deliberately provoking the crowd. The three-way political trap: Pilate cannot release a claimed king without appearing to endorse sedition; he cannot condemn an innocent man without injustice; he cannot satisfy the priests without becoming their instrument. His solution — letting the crowd decide — abdicates judicial responsibility.</p>",
"13": "<p><strong>staurosōn / stauron</strong> — crucify! / cross — <em>stauroō</em> (to crucify) from <em>stauros</em> (stake, post, cross). Crucifixion was designed for maximum suffering and public deterrence — reserved for slaves, non-Roman criminals, and political rebels. The naked victim was fixed (usually nailed) to the cross and died from a combination of exposure, dehydration, and asphyxiation. The crowd's demand requires no legal justification in their answer — just the demand.</p>",
"14": "<p><strong>ti gar epoiēsen kakon / perissōs ekraxan</strong> — what evil has he done? / all the more loudly they shouted — Pilate's question (<em>ti kakon epoiēsen</em>, what evil/harm did he do?) is the closest thing to an acquittal in the Markan trial narrative. He finds no basis for the charge but lacks the moral authority to act on this finding. <em>Perissōs</em> (exceedingly, all the more — an intensifier from <em>perisseuo</em>, to exceed, to abound).</p>",
"15": "<p><strong>to hikanon poiēsai / phragellōsas / paredōken</strong> — to satisfy / having flogged / handed over — <em>to hikanon poiēsai</em> (to do enough, to satisfy — a Latinism: <em>satisfacere</em> rendered in Greek) — legal terminology for satisfying a legal demand. <em>Phragellōsas</em> (having flogged — from Latin <em>flagellum</em>, the Roman military scourging whip; leather thongs embedded with bone and metal fragments that could lacerate flesh to the bone). The flogging preceded the crucifixion and often killed the condemned before they reached the cross. <em>Paredōken</em> (handed over) — the final link in the <em>paradidōmi</em> chain.</p>",
"16": "<p><strong>Praitōrion / holēn tēn speiran</strong> — the Praetorium / the whole cohort — <em>Praitōrion</em> (Latin <em>praetorium</em>) — the governor's official residence and headquarters in Jerusalem, either the Antonia Fortress adjacent to the temple or Herod's palace. <em>Speira</em> (cohort — a Roman military unit of approximately 480-600 soldiers; one tenth of a legion). The phrase <em>holēn tēn speiran</em> (the whole cohort) may be hyperbolic, suggesting a large mocking assembly.</p>",
"17": "<p><strong>porphyran / stephanos ex akanthōn</strong> — purple (robe) / crown of thorns — <em>porphyra</em> (purple cloth — the color of imperial and royal robes in Rome; Tyrian purple dye was extraordinarily expensive). The soldiers mock the Messianic claim with the visible symbols of kingship: robe and crown. <em>Akanthōn</em> (thorns) — the crown may have used <em>Ziziphus spina-christi</em> (Christ-thorn) or <em>Poterium spinosum</em>, common thorny plants of Palestine. The mock coronation inverts every element of royal investiture.</p>",
"18": "<p><strong>chaire, basileu tōn Ioudaiōn</strong> — Hail, King of the Jews! — <em>chaire</em> (Hail! / Greetings! — the standard Greek salutation) parodies the Roman imperial acclamation <em>Ave Caesar</em> (Hail Caesar). The soldiers perform a satirical coronation ceremony, complete with the royal greeting, the purple robe, and the crown. In performing the mockery, they unknowingly enact the truth of the title they ridicule.</p>",
"19": "<p><strong>ekalamō etypton autou tēn kephalēn / eneptyon autō / gonypetountes prosekunoun autō</strong> — they beat his head with a reed / spat on him / falling on knees worshiped him — The triad of humiliation: striking with the mock scepter (the reed), spitting (the gesture of ultimate contempt), and parodic worship (<em>proskuneō</em> — the genuine word for kneeling adoration). The soldiers complete the scene of Isaiah 53:3 (despised and rejected) while performing the gestures that are theologically due to the one they are mocking.</p>",
"20": "<p><strong>enepaixan / exagousin auton hina staurōsōsin auton</strong> — they mocked / they lead him out to crucify him — <em>empazō</em> (to mock, play with, treat as a toy) — the mockery complete; now the execution. The shift from imperfect to present tense (<em>exagousin</em>, they lead out — vivid historical present) accelerates the narrative pace. The victim was typically made to carry the horizontal beam (<em>patibulum</em>) of his cross to the execution site.</p>",
"21": "<p><strong>Kyrēnaion / Alexandrou kai Rhouphoy patera / agorogeuousin</strong> — a Cyrenian / father of Alexander and Rufus / they press into service — <em>Kyrēnaios</em> (from Cyrene — a North African city with a large Jewish diaspora community). Mark identifies Simon by his sons: <em>Alexandrou kai Rhouphoy patera</em> (father of Alexander and Rufus) — this parenthetical identifies Simon to a community that knew his sons. Romans 16:13 mentions a Rufus in Rome, possibly the same person. <em>Agoregeuousin</em> (they press into compulsory service — a military requisition term, from Latin <em>angaria</em>).</p>",
"22": "<p><strong>Golgothon / Kranion Topos</strong> — Golgotha / Place of the Skull — <em>Golgothon</em> is Greek transliteration of Aramaic <em>Gulgolta</em> (skull). Mark translates for his audience: <em>Kranion Topos</em> (Place of Skull — <em>kranion</em> is the Greek anatomical term for skull, root of the English cranium). The name likely described the rocky outcrop's shape. The site was apparently a public execution location outside the city walls (Heb 13:12) on a main road, maximizing visibility as deterrence.</p>",
"23": "<p><strong>esmyrnismenon oinon / ouk elaben</strong> — wine mixed with myrrh / he did not take it — <em>smyrna</em> (myrrh — a bitter resinous gum from the Commiphora tree, used medicinally and as an analgesic). Wine with myrrh was offered as a mild painkiller or narcotic before crucifixion. Jesus's refusal (<em>ouk elaben</em>, he did not take) is deliberate — he chooses to face the cross fully conscious. The refusal is consistent with the Gethsemane prayer's eventual submission: he will drink the cup his Father gives him (14:36).</p>",
"24": "<p><strong>staurousin auton / diamerizontai ta himatia / ballon klēron</strong> — they crucified him / they divide his garments / casting lots — Mark records the crucifixion itself in three words: <em>kai staurousin auton</em> (and they crucified him) — no elaboration of the physical details. The narrative moves immediately to the division of garments, a Psalm 22:18 echo: <em>diemerisanto ta himatia mou heautois kai epi ton himatismon mou ebalon klēron</em> (they divided my garments among themselves and cast lots for my clothing). The Scripture is enacted without being cited.</p>",
"25": "<p><strong>hōra tritē / estaurōsan auton</strong> — the third hour / they crucified him — the third hour in Jewish/Roman daytime reckoning is approximately 9 AM (counting from sunrise). This differs from John 19:14, which places the trial still underway at the sixth hour (noon). The discrepancy has generated extensive discussion; most scholars treat it as a difference in timekeeping conventions or in the evangelist's rhetorical purposes. Mark's third-hour crucifixion allows for three hours of darkness (noon to 3 PM, vv.33–37).</p>",
"26": "<p><strong>epigraphē tēs aitias / HO BASILEUS TŌN IOUDAIŌN</strong> — the written notice of the charge / THE KING OF THE JEWS — <em>epigraphē</em> (inscription, written notice) — the <em>titulus</em> (Latin): a placard specifying the condemned's crime, typically carried before him in procession and then fixed above the cross. The charge is not blasphemy (the Sanhedrin's verdict) but sedition — claiming royal authority. In Roman law, this was the capital crime. The irony: the charge is the truth written above his head.</p>",
"27": "<p><strong>lēstas / ek dexiōn / ex euōnymōn</strong> — bandits/rebels / on his right / on his left — <em>lēstai</em> (bandits, rebels — the same word Jesus used at his arrest: as against a <em>lēstēn</em>, 14:48). The placement between two rebels echoes Isaiah 53:12 (<em>meta anomōn elogisthē</em>, he was numbered with the transgressors) — a connection made explicit in v.28 (the textual note below). The positioning <em>ek dexiōn / ex euōnymōn</em> (right / left) ironically fulfills the disciples' request for the seats of honor at his right and left (10:37, 40).</p>",
"28": "<p><em>Textual note:</em> Verse 28 is absent from the earliest and most important manuscripts — Sinaiticus (01), Vaticanus (03), Alexandrinus (02), and other significant witnesses. It appears in later manuscripts and reads: <em>kai eplērōthē hē graphē hē legousa, kai meta anomōn elogisthē</em> (and the scripture was fulfilled which says: he was numbered with the transgressors — Isaiah 53:12). Most modern critical editions (NA28, UBS5) place it in a footnote or omit it. It is a correct theological observation about what is happening, but as a verse it is most likely a scribal addition that made explicit what the narrative implies through v.27.</p>",
"29": "<p><strong>blasphēmountes / kinountes tas kephalas autōn / ouah</strong> — blaspheming / shaking their heads / Aha! — <em>blasphēmountes</em> (speaking injuriously against, blaspheming) — the same verb used for the charge against Jesus (14:64) is now used by the crowd against Jesus. <em>Kinountes tas kephalas autōn</em> (shaking their heads) echoes Psalm 22:7 LXX: <em>pantes hoi theōrountes me exemykterisan me, elalēsan en cheilesin, ekinēsan kephalēn</em> (all who see me mock me; they shoot out the lip, they shake the head). The Passion narrative is saturated with Psalm 22 echoes. <em>Ouah</em> (Aha! — an exclamation of contemptuous triumph).</p>",
"30": "<p><strong>sōson seauton / katabasas apo tou staurou</strong> — save yourself / coming down from the cross — the taunt inverts the Gospel's central paradox: the one who saves others is unable to save himself precisely because he is saving others. <em>Sōson seauton</em> (save yourself) — the imperative uses the same verb (<em>sōzō</em>) that describes Jesus's healing ministry throughout Mark. The crowds unknowingly express the theological truth: self-saving would have meant non-salvation for others.</p>",
"31": "<p><strong>allous esōsen / heauton ou dynatai sōsai</strong> — he saved others / he cannot save himself — the chief priests' mockery contains the Gospel in two clauses. <em>Allous esōsen</em> (he saved others — aorist, completed past acts of salvation) — the healings, exorcisms, raising of the dead. <em>Heauton ou dynatai sōsai</em> (he cannot save himself) — the <em>ou dynatai</em> (cannot) uses the same verb-root as <em>dynamos</em> (power) and echoes 10:27 (<em>para anthrōpois adynaton, all' ou para theō</em>, impossible with humans, but not with God). The salvation of others requires the non-salvation of himself.</p>",
"32": "<p><strong>ho Christos ho basileus Israēl / katabasatō nyn / idōmen kai pisteusōmen</strong> — the Christ, the King of Israel / come down now / that we may see and believe — <em>ho Christos ho basileus Israēl</em> — the scribes combine the Messianic title with the royal designation, formulating the very truth they deny. <em>Idōmen kai pisteusōmen</em> (that we may see and believe) — the conditional structure inverts the Gospel's logic: faith opens to sight, not sight producing faith. Jesus's refusal to perform a sign-miracle here (cf. 8:11–12) is consistent with his entire ministry's logic. <em>Synestaurōmenoi</em> (those crucified with him — even the two rebels join the mockery in Mark).</p>",
"33": "<p><strong>skotos egeneto eph' holēn tēn gēn / heōs hōras enatēs</strong> — darkness came over the whole land / until the ninth hour — <em>skotos</em> (darkness) from noon (<em>hōras hektēs</em>, sixth hour) until 3 PM (<em>hōras enatēs</em>, ninth hour) — three hours. The darkness echoes Amos 8:9: <em>kai estai en tē hēmera ekeinē, legei kyrios, dysetai ho hēlios mesēmbrias</em> (on that day, says the Lord, the sun will go down at noon). Also Exodus 10:21–23 (the darkness plague over Egypt). The darkness is cosmic participation in the death of the Messiah — or in Mark's register, a sign of divine judgment and mourning.</p>",
"35": "<p><strong>Ēlian phōnei</strong> — he is calling Elijah — the confusion between <em>Eloi</em> (Aramaic: my God, from <em>El</em>) and <em>Ēlias</em> (Elijah in Greek) is phonetically plausible: both begin with the <em>el-</em> sound. Whether the bystanders genuinely misheard or were mockingly misrepresenting his cry is debated. Elijah was expected to come as a precursor to the end (Mal 4:5; 3:23 LXX); anticipating that Jesus might summon Elijah adds an eschatological layer to the crowd's response.</p>",
"36": "<p><strong>oxous / spongon / perititheis kalamo / aphete idōmen</strong> — sour wine / sponge / placing on a reed / let us see — <em>oxos</em> (sour wine, vinegar — cheap wine for soldiers and laborers; different from the myrrh-wine offered in v.23). Psalm 69:21 LXX: <em>edōkan eis to brōma mou cholēn kai eis tēn dipsan mou epotisan me oxos</em> (they gave me gall for my food and vinegar for my thirst). The narrator's comment <em>aphete idōmen ei erchetai Ēlias</em> (let us see if Elijah comes) — another instance of the crowds expecting a miraculous rescue that does not come.</p>",
"37": "<p><strong>apheis phōnēn megalēn exepneusen</strong> — letting out a loud voice he breathed his last — <em>exepneusen</em> (he breathed out, expired — from <em>ekpneō</em>: <em>ek-</em> = out + <em>pneō</em> = to breathe; related to <em>pneuma</em>, spirit/breath). The last breath is ordinarily labored and quiet in crucifixion (respiratory failure from hanging). A <em>phōnē megalē</em> (loud cry/voice) at the moment of death is physiologically striking and theologically purposive — it is not a death of exhaustion but a deliberate release. John 19:30 makes the deliberateness explicit: <em>paradōken to pneuma</em> (he handed over the spirit).</p>",
"38": "<p><strong>to katapetasma tou naou eschisthē eis dyo ap' anōthen heōs katō</strong> — the veil of the temple was torn into two from top to bottom — <em>katapetasma</em> (veil, curtain) — either the outer curtain of the sanctuary (visible from the temple court) or the inner veil separating the Holy of Holies (accessible only to the High Priest on Yom Kippur, Lev 16). <em>Eschisthē</em> (was torn — aorist passive of <em>schizō</em>) — the same verb used for the heavens being torn at the baptism (1:10: <em>schizomenous tous ouranous</em>). The tearing of the heavens opened at Jesus's identification as Son; the tearing of the veil accompanies his death. <em>Ap' anōthen heōs katō</em> (from top to bottom — the direction of divine rather than human action).</p>",
"40": "<p><strong>apo makrothen / Maria hē Magdalēnē</strong> — from far off / Mary the Magdalene — <em>apo makrothen</em> (from a distance) — the women maintain the distance the disciples have also kept (Peter followed <em>apo makrothen</em>, 14:54). Three women are named: <em>Maria hē Magdalēnē</em> (Mary the Magdalene — from Magdala on the western shore of the Sea of Galilee; the <em>Magdalēnē</em> title distinguishes her from the other Marys); <em>Maria hē Iakōbou tou mikrou kai Iōsētos mētēr</em> (Mary the mother of James the small/lesser and of Joseph); <em>Salōmē</em> (named only in Mark among the Synoptics).</p>",
"41": "<p><strong>ēkolouthoun autō kai diēkonoun / gynai pollai</strong> — were following him and serving him / many women — <em>ēkolouthoun</em> (were following — imperfect, continuous; the discipleship word) and <em>diēkonoun</em> (were serving/ministering — imperfect; the word for table-service and the word Jesus used for his own mission: <em>diakonēsai</em>, 10:45). Mark retroactively identifies these women as disciples from Galilee using the precise vocabulary of discipleship. <em>Gynai pollai</em> (many women) — their number underscores that the male disciples' flight (14:50) was not the whole story of the community's response to the cross.</p>",
"42": "<p><strong>paraskeuē / prosabbaton</strong> — Preparation Day / pre-Sabbath day — <em>paraskeuē</em> (Preparation — Friday, the day of preparation for the Sabbath) is a technical term found in all four Gospels. <em>Prosabbaton</em> (pre-Sabbath day) is a hapax legomenon in the NT (only here), reinforcing the temporal urgency: burial must occur before sunset when the Sabbath begins (Deut 21:23 requires burial of an executed criminal on the day of death).</p>",
"43": "<p><strong>euschēmōn bouleutēs / prosedechomenos tēn basileian tou theou / tolmēsas</strong> — a respected council member / awaiting the kingdom of God / daring — <em>euschēmōn</em> (respected, prominent, of good standing — the word for social honor). <em>Bouleutēs</em> (council member — a member of the Sanhedrin, which had just condemned Jesus). <em>Prosdechomenos tēn basileian tou theou</em> (waiting/expecting the kingdom of God) — the phrase identifies Joseph as sympathetic to Jesus's message. <em>Tolmēsas eisēlthen pros ton Pilaton</em> (daring, he went in to Pilate) — <em>tolmaō</em> (to dare, be bold) acknowledges that requesting the body of a crucified rebel was an act of political courage.</p>",
"44": "<p><strong>ethaumasen ei ēdē tethnēken / proskaleis ton kentyriōna</strong> — was surprised that he was already dead / summoning the centurion — <em>ethaumasen</em> (was surprised, marveled) — crucifixion typically took 24–72 hours; death in approximately 6 hours was fast (Jesus was crucified at ~9 AM and died at ~3 PM). Pilate's inquiry of the centurion constitutes a de facto death certification — a legal verification of death before releasing the body. The centurion's testimony (v.45) provides the official confirmation.</p>",
"45": "<p><strong>gnous apo tou kentyriōnos / ptōma / edōrēsato tō Iōsēph</strong> — having learned from the centurion / the corpse / he gave it as a gift to Joseph — <em>ptōma</em> (corpse, body of a fallen person — a specific word for a dead body, from <em>piptō</em>, to fall). <em>Edōrēsato</em> (gave as a gift — from <em>dōreomai</em>, to grant, bestow; carries the sense of a favor or gift given from a position of authority). The verb dignifies Joseph's receipt: he is not scavenging but receiving an official grant.</p>",
"46": "<p><strong>sindona / katheilon / enetylixen tē sindoni / mnēmeion / lithos</strong> — linen cloth / took down / wrapped in the linen cloth / tomb / stone — <em>sindōn</em> (fine linen cloth) — the same word for the young man's garment in 14:51–52; a connection many readers have found significant. <em>Katheilen</em> (took down — technical term for taking down a body from a cross). <em>Enetylixen tē sindoni</em> (wrapped in the linen). The tomb is described as <em>lelatomēmenon ek petras</em> (cut out of rock — a rock-cut tomb); <em>lithos</em> (stone) rolled to the entrance — the stone that will concern the women in 16:3.</p>",
"47": "<p><strong>ethēanto / etethē</strong> — they observed / was placed — <em>ethēanto</em> (they beheld, observed — from <em>theaomai</em>, to gaze carefully upon; the root of the English theatre). The two Marys (<em>Maria hē Magdalēnē kai Maria hē Iōsētos</em>) are explicitly noted as witnesses of the burial location. Their observation of <em>pou tethetai</em> (where he was placed) is the narrative link to the resurrection discovery: they know where to find the tomb (16:1–2). The women are the continuity witnesses across burial and resurrection.</p>"
},
"16": {
"1": "<p><strong>diagenoumenou tou sabbatou / ēgorasan arōmata / aleiposin auton</strong> — the Sabbath having passed / bought spices / to anoint him — <em>diagenoumenou</em> (having passed completely — aorist of <em>diaginomai</em>; the Sabbath is over at sunset Saturday). Three women are named: Mary Magdalene, Mary of James, and Salome (consistent with the witnesses at the cross, 15:40). <em>Arōmata</em> (spices, aromatics) for anointing — they had not been able to complete the burial preparation before the Sabbath; the earlier anointing at Bethany (14:8) was anticipatory burial preparation. <em>Aleiposin auton</em> (to anoint him) — the same verb used at Bethany (14:3 cognate).</p>",
"2": "<p><strong>lian prōi / tē mia tōn sabbatōn / anateilantos tou hēliou</strong> — very early / on the first of the week / the sun having risen — <em>lian prōi</em> (extremely early, deep early morning). <em>Tē mia tōn sabbatōn</em> (on the first of the Sabbaths / first day of the week) — the Aramaic/Jewish counting of days; <em>mia</em> (one/first) refers to Sunday. <em>Anateilantos tou hēliou</em> (the sun having risen — genitive absolute) — the precise temporal marker. The darkness of death (the three hours of darkness, 15:33) is over; the first light of the new day frames the discovery.</p>",
"3": "<p><strong>tis apokylisei hēmin ton lithon</strong> — who will roll away the stone for us — <em>apokyliō</em> (to roll away — a compound verb; <em>apo-</em> = away + <em>kyliō</em> = to roll). The practical concern as they approach — they have the spices but not the means to open the tomb. The question is never answered: when they arrive, the answer has already been given by an agent greater than any human helper. The stone becomes in Markan theology a marker of divine action.</p>",
"4": "<p><strong>anakekylismenonl / megas sphodra</strong> — had been rolled back / extremely large — <em>anakekylismenon</em> (had been rolled back — perfect passive of <em>anakylioō</em>; the perfect tense indicates a completed action with present state: it was rolled and remains rolled back). <em>Megas sphodra</em> (very great/large) — the parenthetical note about the stone's size explains why their concern (v.3) was legitimate and why the discovery is unexpected. No human agent is identified as having moved it.</p>",
"5": "<p><strong>neaniskon / stolichn leukēn / exethambethesan</strong> — a young man / white robe — they were greatly alarmed — <em>neaniskos</em> (young man) — this is the third <em>neaniskos</em> in Mark: the unnamed figure of 14:51–52, the young man of 10:20 (variant), and now this figure at the tomb. The white robe (<em>stolē leukē</em>) distinguishes him from the one in the linen cloth: white garments are angelic vestments (Dan 7:9; Rev 7:9). <em>Exethambethesan</em> (were greatly astonished/alarmed — the strongest compound of <em>thambos</em> used in Mark).</p>",
"7": "<p><strong>kai tō Petrō / proagei hymas eis tēn Galilaian / hōs eipen hymin</strong> — and to Peter / he is going before you to Galilee / just as he told you — <em>kai tō Petrō</em> (and to Peter) — Peter's specific naming alongside the disciples is remarkable. He had denied Jesus three times (14:66–72); the specific inclusion of his name in the resurrection message is the re-inclusion of the one who most publicly failed. <em>Proagei</em> (is going before — present tense, ongoing action; the risen Lord goes ahead as a shepherd) echoes 14:28 exactly. <em>Hōs eipen hymin</em> (just as he told you) — the fulfillment of the word spoken before the Passion.</p>",
"8": "<p><strong>ephugon / tromos kai ekstasis / ouden ouden eipon / ephobounto gar</strong> — they fled / trembling and amazement / they said nothing to anyone / for they were afraid — the final verse of the original Gospel (in the best manuscripts). <em>Tromos</em> (trembling — physical trembling of awe and fear) and <em>ekstasis</em> (ecstasy/astonishment — standing outside oneself; the word for trance or profound disorientation before the divine). <em>Ouden ouden eipon</em> (they said nothing to anyone — double <em>ouden</em>, emphatic). The final clause <em>ephobounto gar</em> (for they were afraid) ends with a <em>gar</em> (for) — an unusual and perhaps unprecedented way to end a sentence or a book. Scholars debate whether this was Mark's intended ending (fear as the proper response to the divine encounter) or whether the original ending was lost; the manuscript evidence supports v.8 as the earliest recoverable ending.</p>",
"9": "<p><em>Note on the longer ending (vv.9–20):</em> Verses 9–20 are absent from the two oldest and most important manuscripts (Codex Sinaiticus and Codex Vaticanus) and from the oldest Syriac, Coptic, and Armenian witnesses. Many other manuscripts note its absence or mark it as suspect. The vocabulary and style differ from Mark 1–16:8. Most modern text critics regard it as a later addition (perhaps 2nd century) summarizing resurrection appearances from the other Gospels. Its contents are canonical in the church, but its Markan authorship is doubtful.</p><p><strong>anastas de prōi / ephainē prōton Mariai tē Magdalēnē</strong> — rising early / he appeared first to Mary Magdalene — <em>ephainē</em> (appeared — aorist passive of <em>phainō</em>; also used for resurrection appearances in Matt 28:7). The longer ending begins by identifying the resurrection and the first appearance, filling out what the original ending left unstated.</p>",
"10": "<p><strong>ekeinē poretheisa / tois met' autou genomenois / penthounsin kai klaiousin</strong> — she having gone / to those who had been with him / mourning and weeping — Mary goes to those who had been with Jesus (<em>tois met' autou genomenois</em>) — a roundabout description of the disciples. <em>Penthounsin kai klaiousin</em> (mourning and weeping — the vocabulary of funeral grief): the disciples are in the posture of bereavement when the resurrection news arrives.</p>",
"11": "<p><strong>hoi akousantes hoti zē kai etheathē / ēpistēsan</strong> — those hearing that he was alive and had been seen / disbelieved — <em>zē</em> (is alive — present tense) and <em>etheathē</em> (had been seen — aorist passive of <em>theaomai</em>). <em>Ēpistēsan</em> (disbelieved — aorist of <em>apisteō</em>; the negative of <em>pisteuō</em>, to believe). The theme of disbelief at resurrection testimony runs through the longer ending (vv.11, 13, 14) and parallels Luke's Emmaus narrative.</p>",
"12": "<p><strong>en hetera morphē / hois ek tōn duo bainousin</strong> — in a different form / to two of them as they walked — <em>hetera morphē</em> (different/other form — <em>morphē</em> is the same word as in Phil 2:6–7 for Christ's pre-incarnate and incarnate forms). The reference parallels Luke's Emmaus road account (Luke 24:13–35), though <em>hetera morphē</em> is a unique addition suggesting a changed or transformed appearance.</p>",
"13": "<p><strong>oud' ekeinois episteusan</strong> — they did not believe them either — the triple disbelief structure (vv.11, 13, 14) before the commission (vv.15–18) follows a pattern: persistent unbelief is overcome only by direct encounter with the risen Lord. The emphasis on the disciples' unbelief at the resurrection is consistent with Mark's characteristic portrayal of their failure to understand throughout the Gospel.</p>",
"14": "<p><strong>tois hendeka / ōneidisei tēn apistian autōn kai sklērokardian</strong> — to the Eleven / rebuked their unbelief and hardness of heart — <em>hoi hendeka</em> (the Eleven — the formal designation after Judas's defection). <em>Ōneidisen</em> (rebuked, upbraided — a strong verb of reproach). <em>Apistia</em> (unbelief) and <em>sklērokardia</em> (hardness of heart — the word used for divorce in 10:5 and for the Pharisees' hardness in 3:5) are the two sins addressed. <em>Tois theaasamenois auton egēgermenon</em> (those who had seen him raised) — the disciples disbelieved eyewitness testimony.</p>",
"15": "<p><strong>poreuthentes eis ton kosmon hapanta / kēruxate to euangelion pasē tē ktisei</strong> — going into all the world / proclaim the gospel to all creation — <em>hapanta ton kosmon</em> (all the world — the universal scope). <em>Pasē tē ktisei</em> (to all creation — the most expansive possible framing; <em>ktisis</em> is creation itself, not merely humanity). The commission frames the Gospel's proclamation as cosmically comprehensive, consistent with the longer ending's escalating universalism.</p>",
"16": "<p><strong>pisteuō kai baptistheis sōthēsetai / ho de apistēsas katakrthēsetai</strong> — the one believing and having been baptized will be saved / the one disbelieving will be condemned — the pairing of <em>pisteuō</em> (faith) and <em>baptistheis</em> (baptism) as conditions of salvation links the two sacramental acts. Notably the negative: <em>ho de apistēsas katakrithēsetai</em> (the one not believing will be condemned) — only unbelief (not unbaptized status) is the basis of condemnation, suggesting faith is the central requirement.</p>",
"17": "<p><strong>sēmeia parakolouthēsei tois pisteuousin</strong> — signs will follow those who believe — <em>parakolouthēo</em> (to follow alongside, accompany — a word for consistent consequence rather than isolated miracle). The signs listed: casting out demons (<em>daimonia ekbalousin</em>), speaking in new tongues (<em>glōssais lalēsousin kainais</em>), picking up serpents (<em>opheis arousin</em>) — these paralleled the Acts 2 and Acts 28 experiences of the early church.</p>",
"18": "<p><strong>opheis arousin / ean ti thansimon piōsin / ou mē autous blapsē / ep' arrōstous cheiras epithēsousin</strong> — they will take up snakes / if they drink anything deadly / it will not harm them / they will lay hands on the sick — the list of signs expands on v.17. The handling of snakes echoes Acts 28:3–6 (Paul and the viper at Malta). <em>Ean ti thansimon piōsin</em> (if they drink anything deadly — conditional) — presented as a protective sign, not a command; it became the basis for some later snake-handling sects. <em>Kalōs hexousin</em> (they will be well/recover).</p>",
"19": "<p><strong>anelēphthē / ekathisen ek dexiōn tou theou</strong> — was taken up / sat at the right hand of God — <em>anelēphthē</em> (was taken up — the same verb as Acts 1:11 for the Ascension; also the verb used for Elijah's translation in 2 Kings 2:9–11 LXX). <em>Ekathisen ek dexiōn tou theou</em> (sat at the right hand of God) — the fulfillment of Psalm 110:1 which Jesus cited in 12:36 (<em>ek dexiōn mou kathō</em>) and his own testimony in 14:62 (<em>ek dexiōn... tēs dynameōs</em>). The longer ending's conclusion thus fulfills Jesus's own predictions.</p>",
"20": "<p><strong>ekeinoi de exelthontes ekēruxan pantachou / tou kyriou synergountos kai ton logon bebaiountos</strong> — and they going out proclaimed everywhere / the Lord working with them and confirming the word — <em>ekeinoi de</em> (and they — the Eleven) go out and preach everywhere (<em>pantachou</em>). <em>Tou kyriou synergountos</em> (the Lord working together with them — genitive absolute; <em>synergos</em> = co-worker; God as the disciples' fellow-worker). <em>Bebaiountos ton logon</em> (confirming the word — from <em>bebaioō</em>, to make firm, ratify). The longer ending closes with the divine-human synergy of mission: human proclamation, divine confirmation through signs.</p>"
}
}

def main():
    existing = load_comm('mkt-original', 'mark')
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, MARK_15_16)
    after = sum(len(v) for v in existing.values())
    save_comm('mkt-original', 'mark', existing)
    print(f'  added {after - before} entries (total: {after})')

    import json as _json
    inter = _json.loads((ROOT / 'data' / 'interlinear' / 'mark.json').read_text())
    out = existing
    for ch in ['15', '16']:
        total = len(inter.get(ch, {}))
        present = len(out.get(ch, {}))
        status = 'complete' if present == total else f'MISSING {total - present}'
        print(f'  ch {ch}: {present}/{total} ({status})')
    if all(len(out.get(ch, {})) == len(inter.get(ch, {})) for ch in ['15', '16']):
        print('All verses present')

if __name__ == '__main__':
    main()
